def entropy(labels):
    _, c = np.unique(labels, return_counts=True)
    p = c / c.sum()
    return -np.sum(p * np.log2(p))

def info_gain(parent, left, right):
    n = len(parent)
    child = (len(left)/n)*entropy(left) + (len(right)/n)*entropy(right)
    return entropy(parent) - child
